public void testSetFormatsByArgumentIndex() {
    ExtendedMessageFormat emf = new ExtendedMessageFormat("{0} {1}", Locale.US);
    Format[] formats = new Format[] { NumberFormat.getInstance(), DateFormat.getInstance() };
    try {
        emf.setFormatsByArgumentIndex(formats);
        Format[] retrievedFormats = emf.getFormatsByArgumentIndex();
        assertNotNull("Formats should be set", retrievedFormats);
        assertEquals("Number of formats should match", formats.length, retrievedFormats.length);
        for (int i = 0; i < formats.length; i++) {
            assertEquals("Format at index " + i + " should match", formats[i], retrievedFormats[i]);
        }
    } catch (UnsupportedOperationException e) {
        fail("setFormatsByArgumentIndex should be supported");
    }
}

public void testSetFormatsByArgumentIndexEmpty() {
    ExtendedMessageFormat emf = new ExtendedMessageFormat("{0}", Locale.US);
    Format[] emptyFormats = new Format[] {};
    try {
        emf.setFormatsByArgumentIndex(emptyFormats);
        Format[] retrievedFormats = emf.getFormatsByArgumentIndex();
        assertTrue("Empty formats should be handled", retrievedFormats == null || retrievedFormats.length == 0);
    } catch (UnsupportedOperationException e) {
        fail("setFormatsByArgumentIndex should support empty array");
    }
}
